module median_filter(  
    input [71:0] matrix, // 3x3 matrix flattened (9x8 bits)  
    output reg [7:0] median  
);  
    integer i, j;  
    reg [7:0] obf_sorted [0:8];  

    always @(*) begin  
        // Unpacking the flattened input into an array  
        for (i = 0; i < 9; i = i + 1)  
            obf_sorted[i] = matrix[i*8 +: 8];  

        // Sorting the array using a simple bubble sort  
        for (i = 0; i < 9; i = i + 1)  
            for (j = 0; j < 8 - i; j = j + 1)  
                if (obf_sorted[j] > obf_sorted[j + 1]) begin  
                    // Swap  
                    obf_sorted[j] = obf_sorted[j] ^ obf_sorted[j + 1];  
                    obf_sorted[j + 1] = obf_sorted[j] ^ obf_sorted[j + 1];  
                    obf_sorted[j] = obf_sorted[j] ^ obf_sorted[j + 1];  
                end  

        // The median is the 5th element in the obf_sorted array  
        median = obf_sorted[4];  
    end  
endmodule
